settings.liquid:
{% liquid
  assign inventory_text = 'Only a few items left'
  assign shipping_prefix = 'Ships by'
  assign js_locale = request.locale.iso_code | default: 'en-US' | replace: '_', '-'
  assign current_country_name = localization.country.name | default: 'United States'
%}

<div class="product-block usp_product" data-usp-shipping>
  <style>
    .custom-inventory{
      display:flex;
      justify-content:space-between;
      align-items:center;
      flex-wrap:nowrap;
      gap:10px;
      width:100%;
      margin:0 0 8px;
      padding:6px 8px;
      background:#fff;
      border-radius:6px;
      box-sizing:border-box;
      box-shadow:0 1px 2px rgba(0,0,0,.05);
      position:relative;
      z-index:2;
    }

    .product-form__buttons,
    .product__submit,
    .add-to-cart{
      margin-top:0 !important;
    }

    .cust-inv-left{
      display:flex;
      flex-direction:column;
      gap:6px;
      flex:1 1 auto;
      min-width:0;
    }

    .low-inventory-text{
      display:flex;
      align-items:center;
      gap:6px;
      font-size:12px;
      font-weight:500;
      color:#1a1a1a;
      line-height:1.2;
    }

    .cust-glowing-circle{
      width:9px;
      height:9px;
      min-width:9px;
      background:#ff8a00;
      border-radius:50%;
      box-shadow:0 0 6px rgba(255,138,0,.65);
    }

    .inventory-progress-bar{
      width:140px;
      height:4px;
      background:#ececec;
      border-radius:999px;
      overflow:hidden;
    }

    .progress-inner{
      width:29%;
      height:100%;
      background:#ff8a00;
      border-radius:999px;
    }

    .cust-ship-right{
      display:flex;
      align-items:center;
      gap:6px;
      white-space:nowrap;
      flex:0 0 auto;
    }

    .ship-flag-img{
      width:20px;
      height:15px;
      display:block;
      object-fit:cover;
      border-radius:2px;
      box-shadow:0 0 0 1px rgba(0,0,0,.06);
    }

    .ship-date-text{
      margin:0;
      font-size:12px;
      font-weight:500;
      color:#1a1a1a;
      line-height:1.2;
    }

    @media (max-width:480px){
      .custom-inventory{
        padding:10px 12px;
        gap:8px;
        margin:0 0 6px;
      }

      .low-inventory-text,
      .ship-date-text{
        font-size:11px;
      }

      .inventory-progress-bar{
        width:100px;
      }

      .ship-flag-img{
        width:18px;
        height:14px;
      }
    }
  </style>

  <div class="custom-inventory">
    <div class="cust-inv-left">
      <div class="low-inventory-text">
        <span class="cust-glowing-circle"></span>
        <span>{{ inventory_text }}</span>
      </div>

      <div class="inventory-progress-bar">
        <div class="progress-inner"></div>
      </div>
    </div>

    <div class="cust-ship-right">
      <img
        src="{% if localization.country %}{{ localization.country | image_url: width: 40 }}{% else %}https://flagcdn.com/w40/us.png{% endif %}"
        width="20"
        height="15"
        alt="{{ current_country_name | escape }}"
        loading="lazy"
        class="ship-flag-img"
      >
      <p class="ship-date-text js-ship-date">
        {{ shipping_prefix }} {{ 'now' | date: '%a, %-d %b' }}
      </p>
    </div>
  </div>

  <script>
    (function () {
      var USP_SELECTOR = '[data-usp-shipping]';
      var locale = {{ js_locale | json }};
      var prefix = {{ shipping_prefix | json }};

      function getBlocks(scope) {
        var items = [];

        if (!scope) {
          return Array.prototype.slice.call(document.querySelectorAll(USP_SELECTOR));
        }

        if (scope.matches && scope.matches(USP_SELECTOR)) {
          items.push(scope);
        }

        if (scope.querySelectorAll) {
          items = items.concat(Array.prototype.slice.call(scope.querySelectorAll(USP_SELECTOR)));
        }

        return items;
      }

      function getEstimatedDate() {
        var estimatedDate = new Date();
        estimatedDate.setDate(estimatedDate.getDate() + 1);

        while (estimatedDate.getDay() === 0 || estimatedDate.getDay() === 6) {
          estimatedDate.setDate(estimatedDate.getDate() + 1);
        }

        return estimatedDate;
      }

      function updateShippingDates(scope) {
        var blocks = getBlocks(scope);
        if (!blocks.length) return;

        var formattedDate = getEstimatedDate().toLocaleDateString(locale, {
          weekday: 'short',
          month: 'short',
          day: 'numeric'
        });

        blocks.forEach(function (block) {
          var dateEl = block.querySelector('.js-ship-date');
          if (dateEl) {
            dateEl.textContent = prefix + ' ' + formattedDate;
          }
        });
      }

      function moveBlockAboveBuyButtons(block) {
        if (!block) return;

        var sectionRoot =
          block.closest('.shopify-section') ||
          block.closest('section[id*="shopify-section"]') ||
          block.closest('product-info') ||
          block.closest('.product') ||
          document;

        var buyButtons = sectionRoot.querySelector('buy-buttons');

        if (!buyButtons) {
          buyButtons = document.querySelector('buy-buttons');
        }

        if (!buyButtons) return;

        var targetWrapper = buyButtons.closest('.v-stack.gap-4') || buyButtons.parentElement;
        if (!targetWrapper || !targetWrapper.parentNode) return;

        if (targetWrapper.previousElementSibling === block) return;

        targetWrapper.parentNode.insertBefore(block, targetWrapper);
      }

      function initUSP(scope) {
        var blocks = getBlocks(scope);
        if (!blocks.length) return;

        blocks.forEach(function (block) {
          moveBlockAboveBuyButtons(block);
        });

        updateShippingDates(scope || document);
      }

      function onReady(callback) {
        if (document.readyState === 'loading') {
          document.addEventListener('DOMContentLoaded', callback);
        } else {
          callback();
        }
      }

      var scheduled = false;

      function scheduleInit(scope) {
        if (scheduled) return;
        scheduled = true;

        window.requestAnimationFrame(function () {
          scheduled = false;
          initUSP(scope || document);
        });
      }

      onReady(function () {
        initUSP(document);
      });

      document.addEventListener('shopify:section:load', function (event) {
        initUSP(event.target || document);
      });

      document.addEventListener('shopify:section:reorder', function (event) {
        initUSP(event.target || document);
      });

      var observer = new MutationObserver(function () {
        scheduleInit(document);
      });

      if (document.documentElement) {
        observer.observe(document.documentElement, {
          childList: true,
          subtree: true
        });
      }
    })();
  </script>
</div>
